/**
 * Assign patchPayload into prevState.
 * @param prevState
 * @param patchPayload
 * @returns
 */
export const assign = <T>(prevState: T, patchPayload: Partial<T> | undefined | void): T => {
  if (patchPayload === undefined || prevState === patchPayload) return prevState

  let changed = false
  let nextState: T = prevState
  for (const key of Object.keys(patchPayload)) {
    if (patchPayload[key] === prevState[key] || patchPayload[key] === undefined) continue
    if (!changed) {
      changed = true
      nextState = { ...prevState }
    }
    nextState[key] = patchPayload[key]
  }
  return nextState
}

export const pick = <T extends Record<string, any>>(
  data: T,
  keys?: ReadonlyArray<keyof T>,
): Partial<T> => {
  if (keys === undefined) return data
  const result: Partial<T> = {}
  for (const key of keys) result[key] = data[key]
  return result
}
