import type { GetState, SetState } from 'zustand'
import { assign } from './object'

export type ISyncStateReplacer<T> = (replace: (state: T) => T) => void

export type IStatePatcher<T> = (
  update: (state: T) => Partial<T> | undefined | void | Promise<Partial<T> | undefined | void>,
) => Promise<void>

export type ISyncStatePatcher<T> = (update: (state: T) => Partial<T> | undefined | void) => void

export interface IStateActionApi<T, S extends { state: T }> {
  get: GetState<S>
  set: SetState<S>
  patch: IStatePatcher<T>
  syncPatch: ISyncStatePatcher<T>
}

export function createStatePatcher<T, S extends { state: T }>(
  get: GetState<S>,
  set: SetState<S>,
): [IStatePatcher<T>, ISyncStatePatcher<T>, ISyncStateReplacer<T>] {
  const patch: IStatePatcher<T> = async (update): Promise<void> => {
    const { state } = get()
    const patchedPayload = await update(state)
    const nextState: T = assign(state, patchedPayload)
    set({ state: nextState } as S)
  }
  const syncPatch: ISyncStatePatcher<T> = update => {
    const { state } = get()
    const nextState: T = assign(state, update(state))
    set({ state: nextState } as S)
  }
  const syncReplace: ISyncStateReplacer<T> = update => {
    const { state } = get()
    const nextState: T = update(state)
    set({ state: nextState })
  }
  return [patch, syncPatch, syncReplace]
}
