import { useEvent } from '@kyokuya/react-hooks'
import React from 'react'
import { unstable_batchedUpdates } from 'react-dom'
import type { IStorage } from '../types'
import { createLocalStorage } from '../util'

export interface IAsyncState<T> {
  loading: boolean
  data: T | null
}

export interface IAsyncStateSerializer<T> {
  deserialize(initialData: Partial<T> | null): T | Promise<T>
  serialize(data: T): Partial<T> | Promise<Partial<T>>
}

export interface IUseAsyncStateResult<T> extends IAsyncState<T> {
  save(data: T): Promise<void>
  refetch(): void
}

export function useAsyncState<T>(
  storageKey: string | undefined,
  serializer: IAsyncStateSerializer<T>,
): IUseAsyncStateResult<T> {
  const [data, setData] = React.useState<T | null>(null)
  const [loading, setLoading] = React.useState<boolean>(true)
  const [loadingTick, setLoadingTick] = React.useState<number>(0)
  const storage = React.useMemo<IStorage<Partial<T>> | null>(
    () => (storageKey ? createLocalStorage<Partial<T>>(storageKey) : null),
    [storageKey],
  )

  const loadData = useEvent(
    async (status: { cancelled: boolean; loadingTick: number }): Promise<void> => {
      let result: T
      if (storage === null) {
        result = await serializer.deserialize(null)
      } else {
        try {
          setLoading(true)
          const initialData = await storage.load()
          result = await serializer.deserialize(initialData)
        } catch (error) {
          result = await serializer.deserialize(null)
          console.error('[usePersistentState] error:', error)
        }
      }

      unstable_batchedUpdates(() => {
        if (!status.cancelled && status.loadingTick === loadingTick) {
          setData(result)
        }
        setLoading(false)
      })
    },
  )

  const saveLockRef = React.useRef<boolean>(false)
  const save = useEvent(async (data: T): Promise<void> => {
    if (storage === null) return

    if (!loading && !saveLockRef.current) {
      try {
        saveLockRef.current = true
        const resolveData: Partial<T> = await serializer.serialize(data)
        await storage.save(resolveData)
      } finally {
        saveLockRef.current = false
      }
    }
  })

  const refetch = useEvent((): void => {
    setLoading(false)
    setLoadingTick(tick => tick + 1)
  })

  React.useEffect(() => {
    const status = { cancelled: false, loadingTick }
    void loadData(status)

    return (): void => {
      status.cancelled = true
    }
  }, [loadData, loadingTick])

  return { loading, data, save, refetch }
}
